import 'package:dio/dio.dart';
class AppError implements Exception{AppError(this.message,{this.code,this.fieldErrors=const{}});final String message;final String? code;final Map<String,String> fieldErrors;factory AppError.fromDio(DioException e){final d=e.response?.data;String? code;String? msg;final fields=<String,String>{};if(d is Map){code=d['code']?.toString();msg=d['message']?.toString();final fe=d['fieldErrors'];if(fe is List){for(final x in fe){if(x is Map)fields[x['field']?.toString()??'']=x['message']?.toString()??'';}}else if(fe is Map){fe.forEach((k,v)=>fields[k.toString()]=v.toString());}}return AppError(messageFor(e.response?.statusCode,code,msg),code:code,fieldErrors:fields);}static String messageFor(int? status,String? code,String? msg){if(code=='NICKNAME_ALREADY_EXISTS')return 'Такой ник уже занят.';if(status==400)return msg??'Проверьте введённые данные.';if(status==404)return 'Данные не найдены.';if(status==409)return msg??'Конфликт данных.';if(status==429)return 'Слишком много запросов. Попробуйте позже.';if(status==null)return 'Сервер недоступен. Проверьте подключение.';return msg??'Что-то пошло не так.';}@override String toString()=>message;}
